SELECT a.user_id userId, a.user_account userAccount, a.super_agent_id superAgentId, a.main_currency mainCurrency, a.account_type accountType, a.user_label_id userLabelId, a.risk_level_id riskLevelId, a.account_status accountStatus, a.vip_grade_code vipGrade, a.vip_grade_up vipGradeUp, a.vip_rank vipRank, a.register_time registerTime, a.first_deposit_time firstDepositTime, a.first_deposit_amount firstDepositAmount, a.last_login_time lastLoginTime, b.available_amount centerWalletAmount, a.offline_days offlineDays, a.registry registry, a.site_code siteCode, a.register_ip registerIp, a.last_login_ip lastLoginIp, a.Inviter Inviter, a.friend_invite_code, c.address as ethAddress, d.address as tronAddress, a.area_code as areaCode, a.phone as phone, a.email as email, a.ip_address as ipAddress, b2.available_amount as platAmount FROM user_info a LEFT JOIN user_coin b ON a.user_id = b.user_id LEFT JOIN user_platform_coin b2 ON a.user_id = b2.user_id left join (select ad.user_id, GROUP_CONCAT(ad.address SEPARATOR ',') AS address from hot_wallet_address ad where ad.chain_type='ETH' and ad.network_type='ERC20' group by ad.user_id)c on c.user_id =a.user_id left join (select ad.user_id, GROUP_CONCAT(ad.address SEPARATOR ',') AS address from hot_wallet_address ad where ad.chain_type='TRON' and ad.network_type='TRC20' group by ad.user_id)d on d.user_id =a.user_id
