SELECT myDay, count(user_id) registerNumber FROM ( SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(`register_time`/1000), @@session.time_zone, #{dbZone}), '%Y-%m-%d') myDay, user_id FROM user_info
